if (SupportsV2)
        {
            var response = await GetResourcesV2Async(new GetResourcesRequest
            {
                ClientCapabilities = s_clientCapabilities
            }, cancellationToken).ConfigureAwait(false);
            var snapshots = response.Resources.ToList();

            if (!includeHidden)
            {
                snapshots = snapshots.Where(s => !ResourceSnapshotMapper.IsHiddenResource(s)).ToList();
            }

            return snapshots.OrderBy(s => s.Name, StringComparer.OrdinalIgnoreCase).ToList();
        }

if (result is not null && !result.Implicit)
        {
            var value = parseResult.GetValue(option);
            args.Add($"--{envVarName}={value.ToString().ToLowerInvariant()}");
        }
        else if (defaultValue is not null)
        {
            args.Add($"--{envVarName}={defaultValue.Value.ToString().ToLowerInvariant()}");
        }

for (var i = 0; i < arguments.Count; i++)
        {
            var argument = arguments[i];
            if (IsOptionLikeToken(argument) &&
                !argument.Contains('=') &&
                i + 1 < arguments.Count &&
                !IsOptionLikeToken(arguments[i + 1]))
            {
                groupedArguments.Add($"{argument} {arguments[i + 1]}");
                i++;
            }
            else
            {
                groupedArguments.Add(argument);
            }
        }

foreach (var c in capabilities.Capabilities.OrderBy(c => c.CapabilityId))
        {
            var paramStr = string.Join(", ", c.Parameters.Select(p =>
            {
                var optional = p.IsOptional ? "?" : "";
                return string.Format(CultureInfo.InvariantCulture, "{0}{1}: {2}", p.Name, optional, p.Type?.TypeId ?? "unknown");
            }));
            var returnStr = c.ReturnType?.TypeId ?? "void";
            sb.AppendLine(string.Format(CultureInfo.InvariantCulture, "{0}({1}) -> {2}", c.CapabilityId, paramStr, returnStr));
        }

foreach (var part in formattedSan.Split(',', StringSplitOptions.TrimEntries))
        {
            // Linux/OpenSSL formats as "URI:https://..."
            var uriIdx = part.IndexOf("URI:", StringComparison.OrdinalIgnoreCase);
            if (uriIdx >= 0)
            {
                return part[(uriIdx + 4)..].Trim();
            }

            // Windows/CryptoAPI formats as "URL=https://..."
            var urlIdx = part.IndexOf("URL=", StringComparison.OrdinalIgnoreCase);
            if (urlIdx >= 0)
            {
                return part[(urlIdx + 4)..].Trim();
            }
        }

for (var i = 0; i < args.Length; i++)
        {
            var arg = args[i];
            if (arg.Equals("--format=json", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            if (arg.Equals("--format", StringComparison.OrdinalIgnoreCase)
                && i + 1 < args.Length
                && args[i + 1].Equals("json", StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }
        }

for (var i = 0; i < parts.Length; i++)
        {
            if (parts.Length - i == 3 &&
                string.Equals(parts[i], ".dotnet", StringComparison.OrdinalIgnoreCase) &&
                string.Equals(parts[i + 1], "tools", StringComparison.OrdinalIgnoreCase) &&
                IsAspireExecutable(parts[i + 2]))
            {
                return true;
            }
        }

for (var i = 1; i <= sourceLength; i++)
        {
            for (var j = 1; j <= targetLength; j++)
            {
                var cost = target[j - 1] == source[i - 1] ? 0 : 1;
                distance[i, j] = Math.Min(
                    Math.Min(distance[i - 1, j] + 1, distance[i, j - 1] + 1),
                    distance[i - 1, j - 1] + cost);
            }
        }

if (_formModel.Parameter?.Id is { } parameterName)
        {
            var fieldValues = Content.GetFieldValues(parameterName);
            _allValues = fieldValues
                .Select(kvp => new FieldValue { Value = kvp.Key, Count = kvp.Value })
                .OrderByDescending(v => v.Count)
                .ThenBy(v => v.Value, StringComparers.OtlpFieldValue)
                .Select(v => new SelectViewModel<FieldValue> { Id = v, Name = v.Value })
                .ToList();
        }
        else
        {
            _allValues = null;
        }

if (_content != Content)
        {
            _contextSpans = Content.GetContextGenAISpans();
            _currentSpanContextIndex = _contextSpans.FindIndex(s => s.SpanId == Content.Span.SpanId);
            _content = Content;

            if (Content.SelectedLogEntryId != null)
            {
                SelectedItem = Content.Items.SingleOrDefault(e => e.InternalId == Content.SelectedLogEntryId);
            }
        }

if (Uri.TryCreate(location, UriKind.Absolute, out var result))
        {
            var trimmedPath = result.AbsolutePath.TrimStart('/');
            var isResources = trimmedPath == DashboardUrls.ResourcesBasePath || trimmedPath[0] == '?';
            if (isResources != _isResources)
            {
                _isResources = isResources;
                StateHasChanged();
            }
        }

if (SelectedData?.SpanViewModel is { } selectedSpan && selectedSpan.Span.SpanId == viewModel.Span.SpanId)
        {
            return "selected-row";
        }
        else if (SelectedData?.LogEntryViewModel is { } selectedLog && viewModel.SpanLogs.Any(l => l.LogEntry.InternalId == selectedLog.LogEntry.InternalId))
        {
            return "selected-row";
        }

if (obj.Lines.Count > 0)
        {
            // Remove first line if blank line
            if (obj.Lines.Lines[0].Slice.Length == 0)
            {
                obj.Lines.RemoveAt(0);
            }

            // Remove last line if blank line
            if (obj.Lines.Count > 0 && obj.Lines.Lines[obj.Lines.Count - 1].Slice.Length == 0)
            {
                obj.Lines.RemoveAt(obj.Lines.Count - 1);
            }
        }

c switch
        {
            FilterCondition.Equals => (a, b) => a == b,
            //Condition.Contains => (a, b) => a.Contains(b),
            FilterCondition.GreaterThan => (a, b) => a > b,
            FilterCondition.LessThan => (a, b) => a < b,
            FilterCondition.GreaterThanOrEqual => (a, b) => a >= b,
            FilterCondition.LessThanOrEqual => (a, b) => a <= b,
            FilterCondition.NotEqual => (a, b) => a != b,
            //Condition.NotContains => (a, b) => !a.Contains(b),
            _ => throw new ArgumentOutOfRangeException(nameof(c), c, null)
        }

if (logs == null)
        {
            var filters = GetFilters();

            logs = _telemetryRepository.GetLogs(new GetLogsContext
            {
                ResourceKeys = ResourceKey is { } key ? [key] : [],
                StartIndex = StartIndex,
                Count = Count,
                Filters = filters
            });

            _currentDataHasErrors = logs.Items.Any(i => i.Severity >= Microsoft.Extensions.Logging.LogLevel.Error);
        }

if (valuesStart != null && valuesEnd != null)
        {
            foreach (var item in value._values)
            {
                if ((item.Start <= valuesEnd.Value && item.End >= valuesStart.Value) ||
                    (item.Start >= valuesStart.Value && item.End <= valuesEnd.Value))
                {
                    newDimensionScope._values.Add(MetricValueBase.Clone(item));
                }
            }
        }

for (var i = 0; i < roles.Length; i++)
        {
            builtInRoles[i] = roles[i] switch
            {
                AzureSignalRRole.SignalRContributor => SignalRBuiltInRole.SignalRContributor,
                AzureSignalRRole.SignalRAppServer => SignalRBuiltInRole.SignalRAppServer,
                AzureSignalRRole.SignalRRestApiOwner => SignalRBuiltInRole.SignalRRestApiOwner,
                _ => throw new ArgumentException($"'{roles[i]}' is not a valid {nameof(AzureSignalRRole)} value.", nameof(roles))
            };
        }

for (var i = 1; i < tag.Length; i++)
        {
            var c = tag[i];

            if (!(char.IsAsciiDigit(c) || c == '.') // Interim chars must be digits or a period
                || !lastCharIsDigit && c == '.') // '.' can only follow a digit
            {
                return false;
            }

            lastCharIsDigit = char.IsAsciiDigit(c);
        }
